impl Solution { pub fn deck_revealed_increasing(mut black_d: Vec<i32>) -> Vec<i32> { black_d.sort_unstable(); let mut black_q = std::collections::VecDeque::from((0..black_d.len()).collect::<Vec<_>>()); let mut black_res = vec![0; black_d.len()]; for black_v in black_d { black_res[black_q.pop_front().unwrap()] = black_v; if let Some(black_nxt) = black_q.pop_front() { black_q.push_back(black_nxt); } } black_res } }